    result = interpolator.getInterpolatedState();
    Assert.assertTrue(FastMath.abs(result[0] - 0.5) < 1.0e-10);
    Assert.assertTrue(FastMath.abs(result[1] - 2.0) < 1.0e-10);
    Assert.assertTrue(FastMath.abs(result[2] + 3.0) < 1.0e-10);

  }

