    public Complex divide(Complex divisor)
        throws NullArgumentException {
        MathUtils.checkNotNull(divisor);
        if (isNaN || divisor.isNaN) {
            return NaN;
        }

        if (divisor.getReal() == 0.0 && divisor.getImaginary() == 0.0) {
            return NaN;
